// Get tomorrow's date
const tomorrow = new Date();
tomorrow.setDate(tomorrow.getDate() + 1);

// Format as yyyy-mm-dd
const yyyy = tomorrow.getFullYear();
const mm = String(tomorrow.getMonth() + 1).padStart(2, '0');
const dd = String(tomorrow.getDate()).padStart(2, '0');
const formattedDate = `${yyyy}-${mm}-${dd}`;

// Return as a single item (required by n8n)
return [
  {
    json: {
      tomorrow: formattedDate
    }
  }
];

// Get all input items from the previous node (Google Sheets)
const allRows = $input.all();

// Count the number of rows
const rowCount = allRows.length;

return [
  {
    json: {
      rowCount3: rowCount,
      message3: `Number of shifts messages successfull sent for: ${rowCount}`
    }
  }
];

const allItems = $input.all();

// Count only items that actually contain data
const realRows = allItems.filter(item =>
  item.json &&
  Object.keys(item.json).length > 0
);

const rowCount = realRows.length;

return [
  {
    json: {
      rowCount4: rowCount,
      message4: `Number of shifts with failed messages: ${rowCount}`
    }
  }
];

const now = new Date();
const start = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() + 1, 0, 0, 0));
const end = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() + 2, 0, 0, 0));
const pad = n => String(n).padStart(2, '0');
const dstr = d => `${d.getUTCFullYear()}-${pad(d.getUTCMonth() + 1)}-${pad(d.getUTCDate())}`;
const iso = d => `${dstr(d)}T00:00:00Z`;
return [{ json: { tomorrow: dstr(start), tomorrowStart: iso(start), tomorrowEnd: iso(end) } }];

